<?php
namespace App\Http\Controllers\Api;use App\Http\Controllers\Controller;use App\Http\Resources\ApiResponse;use App\Http\Resources\FarmPlotResource;use App\Models\Farm;use App\Models\FarmPlot;use Illuminate\Http\JsonResponse;use Illuminate\Support\Facades\Auth;class FarmPlotController extends Controller{public function index(string $farmId): JsonResponse{$farm=Farm::findOrFail($farmId);$plots=$farm->plots()->latest()->paginate(20);return new ApiResponse(FarmPlotResource::collection($plots));}public function store(\App\Http\Requests\FarmPlotStoreRequest $request,string $farmId): JsonResponse{$farm=Farm::findOrFail($farmId);if($farm->owner_id!==Auth::id()&&!Auth::user()->isAdmin()){return new ApiResponse(null,'Forbidden',403);}$plot=$farm->plots()->create($request->validated());return new ApiResponse(new FarmPlotResource($plot),'Plot created',201);}public function show(string $farmId,string $plotId): JsonResponse{$farm=Farm::findOrFail($farmId);$plot=$farm->plots()->findOrFail($plotId);return new ApiResponse(new FarmPlotResource($plot));}public function update(\App\Http\Requests\FarmPlotUpdateRequest $request,string $farmId,string $plotId): JsonResponse{$farm=Farm::findOrFail($farmId);if($farm->owner_id!==Auth::id()&&!Auth::user()->isAdmin()){return new ApiResponse(null,'Forbidden',403);}$plot=$farm->plots()->findOrFail($plotId);$plot->update($request->validated());return new ApiResponse(new FarmPlotResource($plot->fresh()));}public function destroy(string $farmId,string $plotId): JsonResponse{$farm=Farm::findOrFail($farmId);if($farm->owner_id!==Auth::id()&&!Auth::user()->isAdmin()){return new ApiResponse(null,'Forbidden',403);}$farm->plots()->findOrFail($plotId)->delete();return new ApiResponse(null,'Plot deleted');}}